const body = $json.body || $json;
const evt = body.event || 'unknown';
const actorName = (body.actor && body.actor.name) ? body.actor.name : 'Jemand';
const appUrl = body.app_url || 'https://ludwig-a11y.github.io/halleluja-os/';
const teamChannel = 'C0A7LTX603Z';
const teamIds = body.team_slack_ids || [];

let text = actorName + ': ' + evt;
let targets = [teamChannel];

if (evt === 'aufgabe_gestartet') {
  const prio = body.prio ? ' (' + body.prio + ')' : '';
  text = '▶ *' + actorName + '* hat losgelegt' + prio + ' — <' + appUrl + '|Woran arbeitest du gerade?>';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'aufgabe_erledigt') {
  if (body.power_activity && body.ziel) {
    text = '⚡ *' + actorName + '* hat eine Power Activity abgeschlossen:\n> *' + (body.aufgabe || '?') + '*\n> Ziel: ' + body.ziel + '\n<' + appUrl + '|App öffnen>';
    if (teamIds.length) targets = teamIds;
  } else {
    // P1 ohne Ziel oder P2/P3 → kein Team-Slack
    targets = [];
  }
} else if (evt === 'big3_erledigt') {
  text = '🏅 *' + actorName + '* hat ein Big-3 Ziel erreicht (KW ' + (body.kw || '?') + ') — <' + appUrl + '|App öffnen>';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'aufgabe_zugewiesen') {
  text = '📋 *' + actorName + '* hat dir eine Aufgabe zugewiesen:\n> *' + (body.aufgabe || '?') + '*';
  if (body.prio) text += ' (' + body.prio + ')';
  if (body.dl) text += ' — fällig: ' + body.dl;
  text += '\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];
} else if (evt === 'meilenstein_erledigt') {
  text = '🎯 *' + actorName + '* hat einen Meilenstein erreicht!\n> ✅ *' + (body.meilenstein || '?') + '*';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'aufgabe_weitergeleitet') {
  text = '↪️ *' + actorName + '* hat deine Aufgabe weitergeleitet:\n> *' + (body.aufgabe || '?') + '*\n> Neuer Zuständiger: *' + (body.weitergeleitet_an || '?') + '*\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];
} else if (evt === 'diskussion') {
  const typ = body.typ || 'Thema';
  const thema = body.thema || '?';
  const notiz = body.notiz ? '\n> 💬 ' + body.notiz : '';
  const bereich = body.bereich && body.bereich !== 'alle' ? ' (für ' + body.bereich + ')' : '';
  text = '🗣️ *' + actorName + '* möchte besprechen:\n> *' + typ + bereich + ':* ' + thema + notiz + '\n\nBitte hier im Thread diskutieren 👇';
} else if (evt === 'wolke_zurueck') {
  const typ = body.typ || 'Wolke';
  text = '↩ *' + actorName + '* hat deine ' + typ + ' zurückgegeben:\n> *' + (body.thema || '?') + '*\nSie ist jetzt im allgemeinen Pool.\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];
} else if (evt === 'blocker') {
  text = '⚠️ *' + actorName + '* meldet einen Blocker:\n> ' + (body.blocker || '?');
} else if (evt === 'blocker_geloest') {
  text = '✅ *' + actorName + '* hat deinen Blocker aufgelöst. Weiter geht\'s! 💪\n<' + appUrl + '|App öffnen>';
  if (body.an_slack_id) targets = [body.an_slack_id];
} else if (evt === 'aufgabe_zurueckgegeben') {
  const grund = body.grund ? '\n> 💬 ' + body.grund : '';
  text = '↩ *' + actorName + '* hat deine Aufgabe zurückgegeben:\n> *' + (body.aufgabe || '?') + '*' + grund + '\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];

// ── Decision Requests ──────────────────────────────────────────
} else if (evt === 'entscheidung_angefragt') {
  const prio = body.prioritaet || 'mittel';
  const prioEmoji = prio === 'hoch' ? '🔴' : prio === 'mittel' ? '🟡' : '⚪';
  const deadline = body.deadline || '?';
  const blockiert = body.blockiert ? '\n> ⛔ *Stillstand:* ' + body.blockiert : '';
  text = '⚖️ *' + actorName + '* fragt eine Entscheidung an:\n> ' + prioEmoji + ' *' + (body.frage || '?') + '*' + blockiert + '\n> Fällig: ' + deadline + '\n<' + appUrl + '|In der App ansehen & entscheiden>';
  // DM an adressierte Person
  targets = body.an_slack_id ? [body.an_slack_id] : [];
  // GF als CC
  if (body.gf_slack_ids && body.gf_slack_ids.length) {
    body.gf_slack_ids.forEach(id => { if (!targets.includes(id)) targets.push(id); });
  }
  if (!targets.length) targets = [teamChannel];
} else if (evt === 'entscheidung_getroffen') {
  text = '✅ *Entscheidung getroffen* von ' + actorName + ':\n> *Frage:* ' + (body.frage || '?') + '\n> *Beschluss:* ' + (body.beschluss || '?') + '\n> *Warum:* ' + (body.warum || '?') + '\n<' + appUrl + '|In der App ansehen>';
  targets = body.an_slack_id ? [body.an_slack_id] : [teamChannel];
} else if (evt === 'entscheidung_zurueck') {
  text = '↩ *Entscheidungsanfrage zurückgegeben* von ' + actorName + ':\n> *Frage:* ' + (body.frage || '?') + '\n> *Begründung:* ' + (body.begruendung || '?') + '\n<' + appUrl + '|In der App ansehen>';
  targets = body.an_slack_id ? [body.an_slack_id] : [teamChannel];
} else if (evt === 'entscheidung_weitergeleitet') {
  const notiz = body.notiz ? '\n> 💬 ' + body.notiz : '';
  text = '→ *Entscheidungsanfrage weitergeleitet* von ' + actorName + ':\n> *Frage:* ' + (body.frage || '?') + notiz + '\n<' + appUrl + '|In der App ansehen & entscheiden>';
  targets = body.an_slack_id ? [body.an_slack_id] : [teamChannel];
}

const result = targets.map(ch => ({ json: { channel: ch, text: text } }));
if (evt === 'aufgabe_erledigt' && body.actor_slack_id) {
  const prio = body.prio ? ' (' + body.prio + ')' : '';
  result.push({ json: { channel: body.actor_slack_id, text: '🎉 Geschafft!' + prio + ' Weiter so 💪 — <' + appUrl + '|App öffnen>' } });
}
if (evt === 'aufgabe_gestartet' && body.actor_slack_id) {
  const prio = body.prio ? ' (' + body.prio + ')' : '';
  result.push({ json: { channel: body.actor_slack_id, text: '💪 Los geht\'s!' + prio + ' Du packst das — <' + appUrl + '|App öffnen>' } });
}
return result;
